 94→    /// 固定使用 2x Retina scale 渲染（幾乎所有 Mac 都是 Retina，非 Retina 顯示 2x 無害）
 95→    private static let renderScale: CGFloat = 2.0
 96→
 97→    private func renderPDFPage(url: URL, pageIndex: Int) -> NSImage? {
 98→        let backingScale = Self.renderScale
 99→        // 早期取消檢查
100→        guard !Task.isCancelled else { return nil }
101→
102→        // 1. 取得或建立 PDFDocument
103→        let doc: PDFDocument
104→        if let cached = pdfDocumentCache[url] {
105→            doc = cached
106→        } else {
107→            guard let newDoc = PDFDocument(url: url) else { return nil }
108→            pdfDocumentCache[url] = newDoc
109→            doc = newDoc
110→        }
111→
112→        // 載入文件後檢查
113→        guard !Task.isCancelled else { return nil }
114→
115→        guard let page = doc.page(at: pageIndex) else { return nil }
116→
117→        // 2. 取得頁面尺寸（考慮旋轉後的實際顯示尺寸）
118→        let pageBounds = page.bounds(for: .cropBox)
119→        let rotation = page.rotation
120→
121→        // 計算旋轉後的實際顯示尺寸（points）
122→        let pointSize: CGSize
123→        if rotation == 90 || rotation == 270 {
124→            // 旋轉 90 或 270 度時，寬高互換
125→            pointSize = CGSize(width: pageBounds.height, height: pageBounds.width)
126→        } else {
127→            pointSize = pageBounds.size
128→        }
129→
130→        // 3. 建立 NSBitmapImageRep 以支援 Retina 縮放
131→        let pixelSize = CGSize(
132→            width: pointSize.width * backingScale,
133→            height: pointSize.height * backingScale
134→        )
135→
136→        // 像素上限保護：超過 1 億像素（≈400MB RGBA）時跳過，防止極大頁面 OOM
137→        let totalPixels = pixelSize.width * pixelSize.height
138→        guard totalPixels > 0, totalPixels <= 100_000_000 else { return nil }
139→
140→        guard let bitmapRep = NSBitmapImageRep(
141→            bitmapDataPlanes: nil,
142→            pixelsWide: Int(pixelSize.width),
143→            pixelsHigh: Int(pixelSize.height),
144→            bitsPerSample: 8,
145→            samplesPerPixel: 4,
146→            hasAlpha: true,
147→            isPlanar: false,
148→            colorSpaceName: .deviceRGB,
149→            bytesPerRow: 0,  // 讓 CG 自動對齊
150→            bitsPerPixel: 0
151→        ) else { return nil }
152→
153→        // 4. 建立 NSImage 並加入 bitmap representation
154→        let image = NSImage(size: pointSize)
155→        image.addRepresentation(bitmapRep)
156→
157→        // 5. 使用 NSGraphicsContext 繪製
158→        guard let ctx = NSGraphicsContext(bitmapImageRep: bitmapRep) else { return nil }
159→        NSGraphicsContext.saveGraphicsState()
160→        NSGraphicsContext.current = ctx
161→
162→        let cgCtx = ctx.cgContext
163→
164→        // 6. 套用 scale 變換以配合 pixel 尺寸
165→        cgCtx.scaleBy(x: backingScale, y: backingScale)
166→
167→        // 7. 填白色背景
168→        cgCtx.setFillColor(CGColor.white)
169→        cgCtx.fill(CGRect(origin: .zero, size: pointSize))
170→
171→        // 8. 處理旋轉變換
172→        if rotation != 0 {
173→            cgCtx.saveGState()
174→
175→            // 平移到中心點
176→            cgCtx.translateBy(x: pointSize.width / 2, y: pointSize.height / 2)
177→            // 旋轉（rotation 是度數，需轉弧度；負號因為 CG 座標系 Y 軸向上）
178→            cgCtx.rotate(by: -CGFloat(rotation) * .pi / 180)
179→            // 平移回去（基於原始 pageBounds）
180→            cgCtx.translateBy(x: -pageBounds.width / 2, y: -pageBounds.height / 2)
181→        }
182→
183→        // 9. 繪製 PDF 頁面
184→        page.draw(with: .cropBox, to: cgCtx)
185→
186→        if rotation != 0 {
187→            cgCtx.restoreGState()
188→        }
189→
190→        NSGraphicsContext.restoreGraphicsState()
191→        return image
192→    }
