391→        guard scaledHeights.indices.contains(index) else { return }
392→
393→        let scaledHeight = scaledHeights[index]
394→        let scaledSize = NSSize(width: containerWidth, height: scaledHeight)
395→
396→        onCurrentImageChanged?(index, scaledSize)
