 3→/// Monitors system memory pressure and invokes callbacks.
 4→/// Used as safety net for extreme memory situations.
 5→@MainActor
 6→final class MemoryPressureMonitor {
 7→    enum PressureLevel: Equatable {
 8→        case warning, critical
 9→    }
10→
11→    var onPressure: ((PressureLevel) -> Void)?
12→
13→    private var source: (any DispatchSourceMemoryPressure)?
14→
15→    func start() {
16→        guard source == nil else { return }  // Idempotent — avoid leaking duplicate sources
17→        let source = DispatchSource.makeMemoryPressureSource(eventMask: [.warning, .critical], queue: .main)
18→        source.setEventHandler { [weak self] in
19→            guard let self else { return }
20→            let event = source.data
21→            if event.contains(.critical) {
22→                self.onPressure?(.critical)
23→            } else if event.contains(.warning) {
24→                self.onPressure?(.warning)
25→            }
26→        }
27→        source.resume()
28→        self.source = source
29→    }
30→
31→    func stop() {
32→        source?.cancel()
33→        source = nil
34→    }
35→
36→    /// Test-only: simulate a pressure event.
37→    func _testSimulatePressure(_ level: PressureLevel) {
38→        onPressure?(level)
39→    }
40→}
