212→    /// 讀取圖片尺寸（不解碼完整圖片）用於 continuous scroll 模式
213→    /// - Parameter url: 圖片 URL
214→    /// - Returns: 圖片尺寸，已處理 EXIF orientation 5-8 的交換
215→    func getImageSize(for url: URL) async -> NSSize? {
216→        // PDF: 返回 nil（由其他邏輯處理）
217→        guard !Self.isPDFURL(url) else { return nil }
218→
219→        guard let source = CGImageSourceCreateWithURL(url as CFURL, nil),
220→              let props = CGImageSourceCopyPropertiesAtIndex(source, 0, nil) as? [String: Any] else {
221→            return nil
222→        }
223→
224→        let w = (props[kCGImagePropertyPixelWidth as String] as? CGFloat) ?? 0
225→        let h = (props[kCGImagePropertyPixelHeight as String] as? CGFloat) ?? 0
226→        guard w > 0, h > 0 else { return nil }
227→
228→        // 處理 EXIF orientation 5-8（90/270 度旋轉)
229→        // 這些 orientation 的 pixel dimensions 需要交換
230→        let orientation = (props[kCGImagePropertyOrientation as String] as? Int) ?? 1
231→        if orientation >= 5 && orientation <= 8 {
232→            return NSSize(width: h, height: w)
233→        }
234→        return NSSize(width: w, height: h)
235→    }
236→
237→    /// 使用 CGImageSourceCreateThumbnailAtIndex 快速解碼縮圖，同時讀取 full-res 尺寸
238→    /// 共用同一個 CGImageSource，避免二次開檔
239→    private static func decodeThumbnailWithDimensions(at url: URL, maxSize: CGFloat) -> (image: NSImage, fullSize: CGSize)? {
240→        guard !isPDFURL(url) else { return nil }
241→        let decodeStart = CFAbsoluteTimeGetCurrent()
242→
243→        guard let source = CGImageSourceCreateWithURL(url as CFURL, nil) else { return nil }
244→        let sourceMs = (CFAbsoluteTimeGetCurrent() - decodeStart) * 1000
245→
246→        // 讀 full-res dimensions（同一個 source，零額外 I/O）
247→        let fullSize: CGSize
248→        if let props = CGImageSourceCopyPropertiesAtIndex(source, 0, nil) as NSDictionary?,
249→           let w = (props[kCGImagePropertyPixelWidth] as? NSNumber)?.intValue,
250→           let h = (props[kCGImagePropertyPixelHeight] as? NSNumber)?.intValue,
251→           w > 0, h > 0 {
252→            fullSize = CGSize(width: w, height: h)
253→        } else {
254→            fullSize = .zero  // fallback: caller 會用 thumbnail size
255→        }
256→
257→        var options: [CFString: Any] = [
258→            kCGImageSourceCreateThumbnailFromImageAlways: true,
259→            kCGImageSourceCreateThumbnailWithTransform: true,
260→            kCGImageSourceThumbnailMaxPixelSize: maxSize,
261→        ]
262→        // Phase 3.1: SubsampleFactor for JPEG/HEIF DCT fast path at micro-thumbnail sizes
263→        let subsample: Int
264→        if maxSize <= Constants.quickGridSubsampleThresholdPx {
265→            subsample = 4
266→            options[kCGImageSourceSubsampleFactor] = subsample
267→        } else {
268→            subsample = 1
269→        }
270→        let thumbStart = CFAbsoluteTimeGetCurrent()
271→        guard let cgImage = CGImageSourceCreateThumbnailAtIndex(source, 0, options as CFDictionary)
272→        else { return nil }
273→        let thumbMs = (CFAbsoluteTimeGetCurrent() - thumbStart) * 1000
274→
275→        let image = NSImage(cgImage: cgImage, size: NSSize(
276→            width: cgImage.width,
277→            height: cgImage.height
278→        ))
279→        let totalMs = (CFAbsoluteTimeGetCurrent() - decodeStart) * 1000
280→        GridPerfLog.log(String(format: "decode: total=%.2fms | source=%.2fms | thumb(%dx%d→%.0f,ss=%d)=%.2fms | %@",
281→                               totalMs, sourceMs, cgImage.width, cgImage.height, maxSize, subsample, thumbMs,
282→                               url.lastPathComponent))
283→
284→        let effectiveSize = fullSize == .zero ? image.size : fullSize
285→        return (image, effectiveSize)
286→    }
287→
288→    /// 使用 ImageIO 高效解碼（比 NSImage(contentsOf:) 更高效）
289→    private static func decodeImage(at url: URL) -> NSImage? {
290→        guard let source = CGImageSourceCreateWithURL(url as CFURL, nil) else { return nil }
291→        let options: [CFString: Any] = [
292→            kCGImageSourceShouldCache: true,
293→            kCGImageSourceShouldAllowFloat: true
294→        ]
295→        guard let cgImage = CGImageSourceCreateImageAtIndex(source, 0, options as CFDictionary)
296→        else { return nil }
297→        return NSImage(cgImage: cgImage, size: NSSize(
298→            width: cgImage.width,
299→            height: cgImage.height
300→        ))
301→    }
302→
303→    /// 預載用的圖片載入（支援 cooperative cancellation）
304→    private func loadImageCooperative(at url: URL) async -> NSImage? {
305→        if let cached = cache[url] { return cached }
306→        guard !Task.isCancelled else { return nil }
307→
308→        // 使用 Task 而非 Task.detached 以繼承 cancellation scope
309→        let image = await Task(priority: .userInitiated) { () -> NSImage? in
310→            guard !Task.isCancelled else { return nil }
311→            return Self.decodeImage(at: url)
312→        }.value
313→
314→        guard !Task.isCancelled else { return nil }
315→        if let image { cache[url] = image }
316→        return image
317→    }
318→
319→    /// 取消指定 item 的預載任務
320→    func cancelLoad(for item: ImageItem) {
321→        if let pageIndex = item.pdfPageIndex {
322→            let key = PDFCacheKey(url: item.url, pageIndex: pageIndex)
323→            prefetchTasks[key]?.cancel()
324→            prefetchTasks.removeValue(forKey: key)
325→        } else {
326→            imagePrefetchTasks[item.url]?.cancel()
327→            imagePrefetchTasks.removeValue(forKey: item.url)
328→        }
329→    }
330→
331→    /// 預載周圍項目（圖片或 PDF 頁面），釋放遠離的快取
332→    /// 方向性 prefetch：往 direction 方向多預載 prefetchExtra 張
333→    /// ⚠️ 接收值型別參數（ImageItem 是 Sendable struct）避免 Swift 6 Sendable 問題
334→    func updateCache(currentIndex: Int, items: [ImageItem], prefetchDirection: PrefetchDirection = .none) {
335→        guard !items.isEmpty else { return }
336→
337→        let range: ClosedRange<Int>
338→        switch prefetchDirection {
339→        case .forward:
340→            range = max(0, currentIndex - cacheRadius)...min(items.count - 1, currentIndex + cacheRadius + prefetchExtra)
341→        case .backward:
342→            range = max(0, currentIndex - cacheRadius - prefetchExtra)...min(items.count - 1, currentIndex + cacheRadius)
343→        case .none:
344→            range = max(0, currentIndex - cacheRadius)...min(items.count - 1, currentIndex + cacheRadius)
345→        }
346→
347→        // 計算需要的 keys
348→        let activeImageURLs = Set(items[range].filter { !$0.isPDF }.map(\.url))
349→        let activePDFKeys = Set(items[range].compactMap { item in
350→            item.pdfPageIndex.map { PDFCacheKey(url: item.url, pageIndex: $0) }
351→        })
352→        let activePDFURLs = Set(items[range].filter { $0.isPDF }.map(\.url))
353→
354→        // 取消不在範圍內的預載任務
355→        for (url, task) in imagePrefetchTasks where !activeImageURLs.contains(url) {
356→            task.cancel()
357→            imagePrefetchTasks.removeValue(forKey: url)
358→        }
359→        for (key, task) in prefetchTasks where !activePDFKeys.contains(key) {
360→            task.cancel()
361→            prefetchTasks.removeValue(forKey: key)
362→        }
363→
364→        // 釋放超出範圍的快取
365→        cache = cache.filter { activeImageURLs.contains($0.key) }
366→        thumbnailCache = thumbnailCache.filter { activeImageURLs.contains($0.key.url) }
367→        pdfCache = pdfCache.filter { activePDFKeys.contains($0.key) }
368→        pdfDocumentCache = pdfDocumentCache.filter { activePDFURLs.contains($0.key) }
369→
370→        // 啟動新的預載任務（可追蹤、可取消）
371→        for i in range {
372→            let item = items[i]
373→            if let pageIndex = item.pdfPageIndex {
374→                let key = PDFCacheKey(url: item.url, pageIndex: pageIndex)
375→                if pdfCache[key] == nil && prefetchTasks[key] == nil {
376→                    prefetchTasks[key] = Task {
377→                        defer { prefetchTasks.removeValue(forKey: key) }
378→                        guard !Task.isCancelled else { return }
379→                        _ = await loadPDFPage(url: item.url, pageIndex: pageIndex)
380→                    }
381→                }
382→            } else {
383→                if cache[item.url] == nil && imagePrefetchTasks[item.url] == nil {
384→                    imagePrefetchTasks[item.url] = Task {
385→                        defer { imagePrefetchTasks.removeValue(forKey: item.url) }
386→                        guard !Task.isCancelled else { return }
387→                        _ = await loadImageCooperative(at: item.url)
388→                    }
389→                }
390→            }
391→        }
392→    }
393→
394→    /// 清空縮圖快取（Quick Grid dismiss 後呼叫，避免 240px 小圖殘留污染主畫面 fallback）
395→    func clearThumbnailCache() {
396→        thumbnailCache.removeAll()
397→    }
398→
399→    /// 取消所有預載任務並清空縮圖快取
400→    func cancelAllPrefetchTasks() {
401→        for (_, task) in prefetchTasks { task.cancel() }
402→        for (_, task) in imagePrefetchTasks { task.cancel() }
403→        prefetchTasks.removeAll()
404→        imagePrefetchTasks.removeAll()
405→        thumbnailCache.removeAll()
406→    }
407→}
