  5→/// 方向性 prefetch：往翻頁方向多預載
  6→enum PrefetchDirection {
  7→    case none
  8→    case forward
  9→    case backward
 10→}
 11→
 12→/// 使用 actor 確保快取的執行緒安全
 13→actor ImageLoader {
 14→    private var cache: [URL: NSImage] = [:]
 15→    /// 縮圖快取：同時存 image 和 fullSize，避免 cache-hit 時二次開檔
 16→    private struct ThumbnailEntry {
 17→        let image: NSImage
 18→        let fullSize: CGSize
 19→    }
 20→    /// Composite key: same URL with different maxSize produces separate cache entries.
 21→    /// Prevents grid (240/480px) and main view (512px) thumbnails from cross-contaminating.
 22→    private struct ThumbnailCacheKey: Hashable {
 23→        let url: URL
 24→        let maxSize: CGFloat
 25→    }
 26→    private var thumbnailCache: [ThumbnailCacheKey: ThumbnailEntry] = [:]
 27→    private let thumbnailThrottle = ThumbnailThrottle()
 28→    private var pdfCache: [PDFCacheKey: NSImage] = [:]
 29→    private var pdfDocumentCache: [URL: PDFDocument] = [:]
 30→    private let cacheRadius = Constants.cacheRadius
 31→    private let prefetchExtra = Constants.prefetchDirectionExtraCount
 32→
 33→    // 追蹤預載任務（支援取消）
 34→    private var prefetchTasks: [PDFCacheKey: Task<Void, Never>] = [:]
 35→    private var imagePrefetchTasks: [URL: Task<Void, Never>] = [:]
 36→
 37→    /// PDF 頁面快取的 key（固定以 2x Retina 渲染，無需區分 scale）
 38→    private struct PDFCacheKey: Hashable {
 39→        let url: URL
 40→        let pageIndex: Int
 41→    }
 42→
 43→    /// 使用 CGImageSourceCreateThumbnailAtIndex 快速載入低解析度縮圖（JPEG ~16ms）
 44→    /// 同時回傳 full-res dimensions（從同一個 CGImageSource 讀取，避免二次開檔）
 45→    /// PDF 不支援，回傳 nil
 46→    /// - Parameter throttlePriority: Smaller = higher urgency. 0 = highest (default, for non-grid callers).
 47→    ///   Grid callers pass `abs(index - visibleCenter)` as distance-based priority.
 48→    func loadThumbnail(at url: URL, maxSize: CGFloat = 512, priority: TaskPriority = .userInitiated, throttlePriority: Int = 0) async -> (image: NSImage, fullSize: CGSize)? {
 49→        let cacheKey = ThumbnailCacheKey(url: url, maxSize: maxSize)
 50→        if let cached = thumbnailCache[cacheKey] {
 51→            return (cached.image, cached.fullSize)
 52→        }
 53→
 54→        let result = await thumbnailThrottle.withThrottle(priority: throttlePriority) {
 55→            () async -> (image: NSImage, fullSize: CGSize)? in
 56→            // Skip expensive decode if caller was cancelled while waiting in queue
 57→            guard !Task.isCancelled else { return nil }
 58→            return await Task.detached(priority: priority) {
 59→                Self.decodeThumbnailWithDimensions(at: url, maxSize: maxSize)
 60→            }.value
 61→        }
 62→
 63→        // Don't cache if caller's Task was cancelled (e.g. Quick Grid dismissed).
 64→        if let result, !Task.isCancelled {
 65→            thumbnailCache[cacheKey] = ThumbnailEntry(image: result.image, fullSize: result.fullSize)
 66→        }
 67→        return result
 68→    }
 69→
 70→    func loadImage(at url: URL) async -> NSImage? {
 71→        if let cached = cache[url] { return cached }
 72→
 73→        // 在背景 Task 解碼，避免阻塞 MainActor
 74→        let image = await Task.detached(priority: .userInitiated) {
 75→            Self.decodeImage(at: url)
 76→        }.value
 77→
 78→        if let image { cache[url] = image }
 79→        return image
 80→    }
 81→
 82→    // MARK: - PDF Loading
 83→
 84→    func loadPDFPage(url: URL, pageIndex: Int) async -> NSImage? {
 85→        let key = PDFCacheKey(url: url, pageIndex: pageIndex)
 86→        if let cached = pdfCache[key] { return cached }
 87→
 88→        let image = renderPDFPage(url: url, pageIndex: pageIndex)
 89→
 90→        if let image { pdfCache[key] = image }
 91→        return image
 92→    }
 93→
 94→    /// 固定使用 2x Retina scale 渲染（幾乎所有 Mac 都是 Retina，非 Retina 顯示 2x 無害）
 95→    private static let renderScale: CGFloat = 2.0
 96→
 97→    private func renderPDFPage(url: URL, pageIndex: Int) -> NSImage? {
 98→        let backingScale = Self.renderScale
 99→        // 早期取消檢查
100→        guard !Task.isCancelled else { return nil }
101→
102→        // 1. 取得或建立 PDFDocument
103→        let doc: PDFDocument
104→        if let cached = pdfDocumentCache[url] {
105→            doc = cached
106→        } else {
107→            guard let newDoc = PDFDocument(url: url) else { return nil }
108→            pdfDocumentCache[url] = newDoc
109→            doc = newDoc
110→        }
111→
112→        // 載入文件後檢查
113→        guard !Task.isCancelled else { return nil }
114→
115→        guard let page = doc.page(at: pageIndex) else { return nil }
116→
117→        // 2. 取得頁面尺寸（考慮旋轉後的實際顯示尺寸）
118→        let pageBounds = page.bounds(for: .cropBox)
119→        let rotation = page.rotation
120→
121→        // 計算旋轉後的實際顯示尺寸（points）
122→        let pointSize: CGSize
123→        if rotation == 90 || rotation == 270 {
124→            // 旋轉 90 或 270 度時，寬高互換
125→            pointSize = CGSize(width: pageBounds.height, height: pageBounds.width)
126→        } else {
127→            pointSize = pageBounds.size
128→        }
129→
130→        // 3. 建立 NSBitmapImageRep 以支援 Retina 縮放
131→        let pixelSize = CGSize(
132→            width: pointSize.width * backingScale,
133→            height: pointSize.height * backingScale
134→        )
135→
136→        // 像素上限保護：超過 1 億像素（≈400MB RGBA）時跳過，防止極大頁面 OOM
137→        let totalPixels = pixelSize.width * pixelSize.height
138→        guard totalPixels > 0, totalPixels <= 100_000_000 else { return nil }
139→
140→        guard let bitmapRep = NSBitmapImageRep(
141→            bitmapDataPlanes: nil,
142→            pixelsWide: Int(pixelSize.width),
143→            pixelsHigh: Int(pixelSize.height),
144→            bitsPerSample: 8,
145→            samplesPerPixel: 4,
146→            hasAlpha: true,
147→            isPlanar: false,
148→            colorSpaceName: .deviceRGB,
149→            bytesPerRow: 0,  // 讓 CG 自動對齊
150→            bitsPerPixel: 0
151→        ) else { return nil }
152→
153→        // 4. 建立 NSImage 並加入 bitmap representation
154→        let image = NSImage(size: pointSize)
155→        image.addRepresentation(bitmapRep)
156→
157→        // 5. 使用 NSGraphicsContext 繪製
158→        guard let ctx = NSGraphicsContext(bitmapImageRep: bitmapRep) else { return nil }
159→        NSGraphicsContext.saveGraphicsState()
160→        NSGraphicsContext.current = ctx
161→
162→        let cgCtx = ctx.cgContext
163→
164→        // 6. 套用 scale 變換以配合 pixel 尺寸
165→        cgCtx.scaleBy(x: backingScale, y: backingScale)
166→
167→        // 7. 填白色背景
168→        cgCtx.setFillColor(CGColor.white)
169→        cgCtx.fill(CGRect(origin: .zero, size: pointSize))
170→
171→        // 8. 處理旋轉變換
172→        if rotation != 0 {
173→            cgCtx.saveGState()
174→
175→            // 平移到中心點
176→            cgCtx.translateBy(x: pointSize.width / 2, y: pointSize.height / 2)
177→            // 旋轉（rotation 是度數，需轉弧度；負號因為 CG 座標系 Y 軸向上）
178→            cgCtx.rotate(by: -CGFloat(rotation) * .pi / 180)
179→            // 平移回去（基於原始 pageBounds）
180→            cgCtx.translateBy(x: -pageBounds.width / 2, y: -pageBounds.height / 2)
181→        }
182→
183→        // 9. 繪製 PDF 頁面
184→        page.draw(with: .cropBox, to: cgCtx)
185→
186→        if rotation != 0 {
187→            cgCtx.restoreGState()
188→        }
189→
190→        NSGraphicsContext.restoreGraphicsState()
191→        return image
192→    }
