23→    // MARK: - Layer-backed Rendering
24→    override var wantsUpdateLayer: Bool { true }
25→
26→    override func updateLayer() {
27→        guard let layer else { return }
28→        layer.contents = cachedCGImage
29→        layer.contentsScale = window?.backingScaleFactor ?? 2.0
30→    }
31→
32→    // MARK: - Backing Properties Change
33→    override func viewDidChangeBackingProperties() {
34→        super.viewDidChangeBackingProperties()
35→        needsDisplay = true
36→    }
37→
38→    // MARK: - Configuration
39→    func setImage(_ image: NSImage?) {
40→        cachedCGImage = image?.cgImage(forProposedRect: nil, context: nil, hints: nil)
41→        needsDisplay = true
42→    }
