432→    /// - Parameter maxWidth: Target display width in pixels (include Retina scale factor)
433→    func loadImageForDisplay(at url: URL, maxWidth: CGFloat) async -> NSImage? {
434→        let cacheKey = DisplayCacheKey(url: url, maxWidth: maxWidth)
435→        if let cached = displayCache[cacheKey] { return cached }
436→
437→        let image = await Task.detached(priority: .userInitiated) {
438→            Self.decodeImageForDisplay(at: url, maxWidth: maxWidth)
439→        }.value
