447→    /// Decode with subsample for large images, full decode for small ones
448→    private static func decodeImageForDisplay(at url: URL, maxWidth: CGFloat) -> NSImage? {
449→        guard let source = CGImageSourceCreateWithURL(url as CFURL, nil) else {
450→            return decodeImage(at: url)
451→        }
452→
453→        guard let properties = CGImageSourceCopyPropertiesAtIndex(source, 0, nil) as? [CFString: Any],
454→              let pixelWidth = properties[kCGImagePropertyPixelWidth] as? CGFloat,
455→              let pixelHeight = properties[kCGImagePropertyPixelHeight] as? CGFloat else {
456→            return decodeImage(at: url)
457→        }
458→
459→        // EXIF orientation 5-8: swap w/h (sensor dimensions don't match display orientation)
460→        let orientation = properties[kCGImagePropertyOrientation] as? UInt32 ?? 1
461→        let sourceWidth = (orientation >= 5 && orientation <= 8) ? pixelHeight : pixelWidth
462→
463→        // Calculate subsample factor: maxWidth is already in display pixels
464→        let ratio = sourceWidth / maxWidth
465→        let subsampleFactor: Int
466→        if ratio >= 4.0 {
467→            subsampleFactor = 4
468→        } else if ratio >= 2.0 {
469→            subsampleFactor = 2
470→        } else {
471→            // No subsample needed — full decode
472→            return decodeImage(at: url)
473→        }
474→
475→        // Use thumbnail API with subsample for JPEG/HEIF DCT fast path
476→        // CGImageSource scales proportionally from maxWidth
477→        let options: [CFString: Any] = [
478→            kCGImageSourceCreateThumbnailFromImageAlways: true,
479→            kCGImageSourceCreateThumbnailWithTransform: true,
480→            kCGImageSourceThumbnailMaxPixelSize: maxWidth,
481→            kCGImageSourceSubsampleFactor: subsampleFactor,
482→            kCGImageSourceShouldCacheImmediately: true
483→        ]
484→
485→        guard let cgImage = CGImageSourceCreateThumbnailAtIndex(source, 0, options as CFDictionary) else {
486→            return decodeImage(at: url)
487→        }
488→
489→        return NSImage(cgImage: cgImage, size: NSSize(width: cgImage.width, height: cgImage.height))
490→    }
